                        worksheet.getCell("G" + (details.length + 10 + i + 1)).value = '';
                        worksheet.getCell("H" + (details.length + 10 + i + 1)).value = '';
                        worksheet.getCell("I" + (details.length + 10 + i + 1)).value = '';
                    }
                    worksheet.getCell("A" + (details.length + 10 + shiyebu.length + 1)).value = '申请人：' + record.VoucherHead.Creator;
                    worksheet.getCell("D" + (details.length + 10 + shiyebu.length + 1)).value = '主管审核：';
                    worksheet.getCell("G" + (details.length + 10 + shiyebu.length + 1)).value = '上级审批：';
                    
                    // 遍历工作表中的所有行（包括空行）
                    worksheet.eachRow({ includeEmpty: true }, function (row, rowNumber) {
                        row.height = 15;
