                                name: '宋体',
                                family: 4,
                                size: 17,
                                bold: true
                            };
                            row.alignment = { vertical: 'bottom', horizontal: 'center', wrapText: true, shrinkToFit: true };
                            return;
                        } else if (rowNumber == 4) {
                            // 设置字体
                            row.font = {
                                size: 10,
                                name: '宋体',
                            };
                            row.height = 24.75;

                        } else if (rowNumber == (details.length + 10)) {
                            // 设置字体
