                                size: 10,
                                name: '华文中宋',
                            };
                        } 
                        else if (rowNumber == (11 + shiyebu.length + details.length)) {
                            // 设置字体
                            row.font = {
                                size: 11,
                                name: '华文中宋',
                            };
                            row.height = 32;
                            return;
                        }
                        row.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true, shrinkToFit: true };
                        row.eachCell({ includeEmpty: true }, function (cell, colNumber) {
                            if (rowNumber == 2) {
                                row.height = 18.75;
                                if (colNumber < 3) {
                                    cell.font = {
                                        size: 13,
                                        name: '宋体',
                                        bold: true,
                                    };
