                            }
                            if (rowNumber == (10 + details.length)) {
                                cell.fill = {
                                    type: 'pattern',
                                    pattern: 'solid',
                                    fgColor: { argb: 'D8D8D8' },
                                }
                            }
                            if (rowNumber >= (10 +  details.length)) {
                                row.height = 27;
                            }
                            if (rowNumber > 4 && rowNumber < (details.length + 9)) {
                                cell.border = {
                                    top: { style: 'hair' },
