                                    bottom: { style: 'thin' },
                                    right: { style: 'thin' }
                                };
                            }
                            if (rowNumber == 4) {
                                cell.border.top.style = 'medium';
                            }
                            if (colNumber == 1) {
                                cell.border.left.style = 'medium';
                            }
                            if (colNumber == 9) {
                                cell.border.right.style = 'medium';
                            }
                            if (rowNumber == (10 + shiyebu.length + details.length)) {
                                cell.border.bottom.style = 'medium';
                            }
                            if (rowNumber == (9 + details.length)) {
                                cell.border.left.style = 'medium';
                                cell.border.top.style = 'medium';
                                cell.border.bottom.style = 'medium';
                            }
                            if (rowNumber > (9 + details.length)) {
                                if (colNumber == 2 || colNumber == 3)
                                    cell.border.left.style = 'medium';
                            }
                        });
                    });
                                     
                    worksheet.views = [
                        { state: 'normal', activeCell: 'A1', style: 'pageBreakPreview' }
                    ];
                    worksheet.pageSetup.printArea = 'A1:I' + (11 + shiyebu.length + details.length);
