                     //    saveAs(blob, 'vvull.xlsx');
                     //})
                  
                     
                },
                async createPicture(msg) {
                    let imgData = "";
                    if (document.getElementById("qrCode") != null)
                        document.body.removeChild(document.getElementById("qrCode"));
                    var aa = document.createElement("DIV");
                    aa.setAttribute("id", "qrCode");
                    //设置div背景色
                    aa.style.backgroundColor = "#F0F2F5";
                    document.body.appendChild(aa);
                    new QRCode(document.getElementById("qrCode"), {
                        text: msg,
                        width: 108,
                        height: 82,
                        colorDark: '#333333', // 二维码颜色
                        colorLight: '#ffffff', // 二维码背景色
                        correctLevel: QRCode.CorrectLevel.L// 容错率，L/M/H
                   });
                    await html2canvas(document.getElementById("qrCode"), {
                        backgroundColor: null,
                        width: 108,
                        height: 82
                    }).then(canvas => {
                        imgData = canvas.toDataURL('image/jpeg')
                        if (document.getElementById("qrCode") != null)
                            document.body.removeChild(document.getElementById("qrCode"));
                        });
                    return imgData;
                }
